import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/SupabaseContext';
import { useBrand } from '../context/BrandContext';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';

interface Generation {
  id: string;
  target_company: string;
  match_score: number;
  application_status: string;
  created_at: string;
  missing_keywords?: string[];
}

export default function AnalyticsDashboard() {
  const { user, supabase, isPremium, isLoading } = useAuth();
  const brand = useBrand();
  const navigate = useNavigate();
  const [generations, setGenerations] = useState<Generation[]>([]);

  useEffect(() => {
    if (isLoading) return;
    if (!user) { navigate('/login'); return; }

    async function load() {
      const { data } = await supabase
        .from('generations')
        .select('id, target_company, match_score, application_status, created_at, missing_keywords')
        .eq('user_id', user!.id)
        .order('created_at', { ascending: false });
      if (data) setGenerations(data);
    }
    load();
  }, [user, supabase, isLoading, navigate]);

  if (isLoading) return null;

  // Compute analytics
  const statusCounts = generations.reduce((acc, g) => {
    const s = g.application_status || 'tailored';
    acc[s] = (acc[s] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const funnelData = [
    { name: 'Tailored', value: statusCounts.tailored || 0, fill: '#8b5cf6' },
    { name: 'Applied', value: statusCounts.applied || 0, fill: '#3b82f6' },
    { name: 'Interview', value: statusCounts.interviewing || 0, fill: '#f59e0b' },
    { name: 'Offer', value: statusCounts.offer || 0, fill: '#10b981' },
    { name: 'Rejected', value: statusCounts.rejected || 0, fill: '#ef4444' },
  ];

  // Weekly activity (last 8 weeks)
  const weeklyData: { week: string; count: number }[] = [];
  const now = new Date();
  for (let i = 7; i >= 0; i--) {
    const start = new Date(now);
    start.setDate(start.getDate() - (i + 1) * 7);
    const end = new Date(now);
    end.setDate(end.getDate() - i * 7);
    const count = generations.filter(g => {
      const d = new Date(g.created_at);
      return d >= start && d < end;
    }).length;
    weeklyData.push({
      week: `W${8 - i}`,
      count,
    });
  }

  // Top missing keywords
  const keywordCounts: Record<string, number> = {};
  generations.forEach(g => {
    (g.missing_keywords || []).forEach(kw => {
      keywordCounts[kw] = (keywordCounts[kw] || 0) + 1;
    });
  });
  const topKeywords = Object.entries(keywordCounts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 10);

  // Average match score
  const scores = generations.filter(g => g.match_score > 0).map(g => g.match_score);
  const avgScore = scores.length > 0 ? Math.round(scores.reduce((a, b) => a + b, 0) / scores.length) : 0;

  // Success rate
  const applied = (statusCounts.applied || 0) + (statusCounts.interviewing || 0) + (statusCounts.offer || 0);
  const successRate = applied > 0 ? Math.round(((statusCounts.interviewing || 0) + (statusCounts.offer || 0)) / applied * 100) : 0;

  return (
    <div style={{ maxWidth: '1000px', margin: '0 auto', padding: '2rem 1.5rem' }}>
      <h1 style={{ fontSize: '1.5rem', marginBottom: '2rem', color: 'var(--text-primary)' }}>
        <i className="fa-solid fa-chart-line" style={{ marginRight: '0.5rem', color: brand.primaryColor }} />
        Analytics
      </h1>

      {/* Summary Cards */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(160px, 1fr))', gap: '1rem', marginBottom: '2rem' }}>
        {[
          { label: 'Total Applications', value: generations.length, color: brand.primaryColor },
          { label: 'Avg Match Score', value: `${avgScore}%`, color: '#f59e0b' },
          { label: 'Callback Rate', value: `${successRate}%`, color: '#10b981' },
          { label: 'Offers', value: statusCounts.offer || 0, color: '#8b5cf6' },
        ].map(card => (
          <div
            key={card.label}
            className="glass-panel"
            style={{ padding: '1.25rem', textAlign: 'center' }}
          >
            <div style={{ fontSize: '2rem', fontWeight: 700, color: card.color }}>{card.value}</div>
            <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', textTransform: 'uppercase' }}>{card.label}</div>
          </div>
        ))}
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(400px, 1fr))', gap: '1.5rem' }}>
        {/* Application Funnel */}
        <div className="glass-panel" style={{ padding: '1.5rem' }}>
          <h3 style={{ fontSize: '0.95rem', marginBottom: '1rem', color: 'var(--text-primary)' }}>Application Funnel</h3>
          <ResponsiveContainer width="100%" height={250}>
            <BarChart data={funnelData}>
              <XAxis dataKey="name" tick={{ fill: 'var(--text-secondary)', fontSize: 12 }} />
              <YAxis tick={{ fill: 'var(--text-secondary)', fontSize: 12 }} />
              <Tooltip contentStyle={{ background: 'var(--panel-bg)', border: '1px solid var(--panel-border)', borderRadius: '8px' }} />
              <Bar dataKey="value" radius={[4, 4, 0, 0]}>
                {funnelData.map(entry => (
                  <Cell key={entry.name} fill={entry.fill} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>

        {/* Weekly Activity */}
        <div className="glass-panel" style={{ padding: '1.5rem' }}>
          <h3 style={{ fontSize: '0.95rem', marginBottom: '1rem', color: 'var(--text-primary)' }}>Weekly Activity</h3>
          <ResponsiveContainer width="100%" height={250}>
            <BarChart data={weeklyData}>
              <XAxis dataKey="week" tick={{ fill: 'var(--text-secondary)', fontSize: 12 }} />
              <YAxis tick={{ fill: 'var(--text-secondary)', fontSize: 12 }} />
              <Tooltip contentStyle={{ background: 'var(--panel-bg)', border: '1px solid var(--panel-border)', borderRadius: '8px' }} />
              <Bar dataKey="count" fill={brand.primaryColor} radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Skills Gap */}
      {topKeywords.length > 0 && (
        <div className="glass-panel" style={{ padding: '1.5rem', marginTop: '1.5rem' }}>
          <h3 style={{ fontSize: '0.95rem', marginBottom: '1rem', color: 'var(--text-primary)' }}>
            <i className="fa-solid fa-triangle-exclamation" style={{ color: '#f59e0b', marginRight: '0.4rem' }} />
            Top Missing Keywords (Skills Gap)
          </h3>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: '0.5rem' }}>
            {topKeywords.map(([keyword, count]) => (
              <span
                key={keyword}
                style={{
                  padding: '0.3rem 0.75rem',
                  borderRadius: '2px',
                  background: 'rgba(245,158,11,0.1)',
                  border: '1px dashed rgba(245,158,11,0.2)',
                  color: '#f59e0b',
                  fontSize: '0.8rem',
                }}
              >
                {keyword} <span style={{ opacity: 0.6 }}>({count})</span>
              </span>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}
